mapper.select:
SELECT AREA_NO
  FROM AREA_TBL
 WHERE AREA_CODE = ${areaCode}

SELECT SIGUNGU_NO
  FROM SIGUNGU_TBL
 WHERE AREA_NO = #{areaNo}
   AND SIGUNGU_CODE = #{sigunguCode}

SELECT ATTRACTION_NO
  FROM TEST_ATTRACTION_WISH_TBL
 WHERE MEMBER_ID = #{memberId}

mapper.delete:
DELETE
  FROM TEST_ATTRACTION_WISH_TBL
 WHERE MEMBER_ID = #{memberId}
   AND ATTRACTION_NO = #{attractionNo}

mapper.select:
SELECT COUNT(*)
FROM TEST_ATTRACTION_WISH_TBL
WHERE MEMBER_ID = #{memberId}
